PlanInitializerScript.Source:
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningPlan.AccountRequest.Operation;
        import sailpoint.object.ProvisioningPlan.AttributeRequest;
        import sailpoint.api.IdentityService;
        import sailpoint.object.Identity;
        import sailpoint.object.Application;
        import sailpoint.object.Attributes;
        import sailpoint.object.Link;
        import sailpoint.object.IdentityRequest;
        import sailpoint.object.Custom;
        import sailpoint.tools.Util;

        if(plan!=null){
			List accReqs = plan.getAccountRequests();
			String idReq = plan.getArguments().get("identityRequestId");

			IdentityService identityService =new IdentityService(context);                
			if ((accReqs != null) && !accReqs.isEmpty()) {
				for (AccountRequest accReq : accReqs) {
					Link racfLink = null;
					if(identity  != null && null != accReq && null != accReq.getApplication()){
						Application app = context.getObjectByName(Application.class,accReq.getApplication());
						List racfLinks = identityService.getLinks(identity,app);

						//adding RequestID and UserName with all accountRequests
						accReq.add(new ProvisioningPlan.AttributeRequest("RecID", ProvisioningPlan.Operation.Set, idReq));  
						if(null != identity && Util.isNotNullOrEmpty(identity.getAttribute("samAccountName"))){
							accReq.add(new ProvisioningPlan.AttributeRequest("UserName", ProvisioningPlan.Operation.Set, identity.getAttribute("samAccountName")));
						}
						else if(null != identity && Util.isNotNullOrEmpty(identity.getName()))
						{
							accReq.add(new ProvisioningPlan.AttributeRequest("UserName", ProvisioningPlan.Operation.Set, identity.getName()));
						}

						if ( accReq  != null && AccountRequest.Operation.Create.equals( accReq.getOperation() ) ) {
							accReq.add(new ProvisioningPlan.AttributeRequest("NeedTPX", ProvisioningPlan.Operation.Set, "1"));
							accReq.add(new ProvisioningPlan.AttributeRequest("ReqFlag", ProvisioningPlan.Operation.Set, "1"));
							accReq.add(new ProvisioningPlan.AttributeRequest("ReqStatus", ProvisioningPlan.Operation.Set, "0"));
							accReq.add(new ProvisioningPlan.AttributeRequest("ReqComment", ProvisioningPlan.Operation.Set, "Approved"));
						}
						else if (accReq  != null && AccountRequest.Operation.Modify.equals( accReq.getOperation()) && null != accReq.getAttributeRequest("entitlement") && null != accReq.getAttributeRequest("entitlement").getOperation() && ProvisioningPlan.Operation.Add.equals(accReq.getAttributeRequest("entitlement").getOperation())){
							accReq.add(new ProvisioningPlan.AttributeRequest("NeedTPX", ProvisioningPlan.Operation.Set, "0"));
							accReq.add(new ProvisioningPlan.AttributeRequest("ReqFlag", ProvisioningPlan.Operation.Set, "0"));
							accReq.add(new ProvisioningPlan.AttributeRequest("ReqStatus", ProvisioningPlan.Operation.Set, "0"));
							accReq.add(new ProvisioningPlan.AttributeRequest("ReqComment", ProvisioningPlan.Operation.Set, "Approved"));

							List racfLinks = identityService.getLinks(identity,app);
							if(null != racfLinks && !racfLinks.isEmpty()){
								racfLink=racfLinks.get(0);

								if(null != racfLink){
									Attributes racfAttrs = racfLink.getAttributes();
									if(null != racfAttrs){
										HashMap attrMap = racfAttrs.getMap();

										if(null != attrMap){
											Iterator itr = attrMap.entrySet().iterator(); 

											while(itr.hasNext()) { 
												Map.Entry entry = itr.next(); 

												if(null != entry.getKey()){
													AttributeRequest attrReq = accReq.getAttributeRequest(entry.getKey());

													if(attrReq == null && entry.getValue() != null ) {
														accReq.add(new AttributeRequest(entry.getKey(),ProvisioningPlan.Operation.Set, entry.getValue()));		
													}

												}
											}
										}
									}
								}
							}
						}
						else if (accReq  != null && AccountRequest.Operation.Modify.equals( accReq.getOperation()) && null != accReq.getAttributeRequest("entitlement") && null != accReq.getAttributeRequest("entitlement").getOperation() && ProvisioningPlan.Operation.Remove.equals(accReq.getAttributeRequest("entitlement").getOperation())){
							String attrName= "";
							accReq.add(new AttributeRequest("ReqType",ProvisioningPlan.Operation.Set, "Remove"));
						
							if(null != identity && Util.isNotNullOrEmpty(identity.getAttribute("samAccountName"))){
								accReq.add(new ProvisioningPlan.AttributeRequest("networkID", ProvisioningPlan.Operation.Set, identity.getAttribute("samAccountName")));
							}
							else if(null != identity && Util.isNotNullOrEmpty(identity.getName()))
							{
								accReq.add(new ProvisioningPlan.AttributeRequest("networkID", ProvisioningPlan.Operation.Set, identity.getName()));
							}

							if(null != racfLinks && !racfLinks.isEmpty()){
								racfLink=racfLinks.get(0);
								accReq.add(new AttributeRequest("tpx_id",ProvisioningPlan.Operation.Set, racfLink.getAttribute("GenTPXID")));	
								accReq.add(new ProvisioningPlan.AttributeRequest("ReqStatus", ProvisioningPlan.Operation.Set, "0"));
								accReq.add(new ProvisioningPlan.AttributeRequest("ReqDate", ProvisioningPlan.Operation.Set, racfLink.getAttribute("ReqDate")));
							}
						}
						else if (accReq  != null && AccountRequest.Operation.Disable.equals(accReq.getOperation())){
						  accReq.add(new AttributeRequest("ReqType",ProvisioningPlan.Operation.Set, "Term"));	
						  if(null != identity && Util.isNotNullOrEmpty(identity.getAttribute("samAccountName"))){
							accReq.add(new ProvisioningPlan.AttributeRequest("networkID", ProvisioningPlan.Operation.Set, identity.getAttribute("samAccountName")));
						  }
						  else if(null != identity && Util.isNotNullOrEmpty(identity.getName()))
						  {
							accReq.add(new ProvisioningPlan.AttributeRequest("networkID", ProvisioningPlan.Operation.Set, identity.getName()));
						  }
						  if(null != racfLinks && !racfLinks.isEmpty()){
							racfLink=racfLinks.get(0);
							accReq.add(new AttributeRequest("tpx_id",ProvisioningPlan.Operation.Set, racfLink.getAttribute("GenTPXID")));	accReq.add(new ProvisioningPlan.AttributeRequest("ReqDate", ProvisioningPlan.Operation.Set, racfLink.getAttribute("ReqDate")));
						  }
						}
					}
				}
			}
        }

